import React from 'react';

export default function UptimeBadge({ status }) {
  const cfg = {
    UP:      { light: 'bg-green-100 text-green-800',  dark: 'dark:bg-transparent dark:text-gh-green-em dark:border dark:border-gh-green-em/40', dot: 'bg-green-500 dark:bg-gh-green-em' },
    DOWN:    { light: 'bg-red-100 text-red-700',      dark: 'dark:bg-transparent dark:text-red-400 dark:border dark:border-red-400/40',          dot: 'bg-red-500' },
    TIMEOUT: { light: 'bg-yellow-100 text-yellow-800',dark: 'dark:bg-transparent dark:text-yellow-400 dark:border dark:border-yellow-400/40',    dot: 'bg-yellow-500' },
    UNKNOWN: { light: 'bg-gray-100 text-gray-500',    dark: 'dark:bg-transparent dark:text-gh-dim dark:border dark:border-gh-dim/40',            dot: 'bg-gray-400 dark:bg-gh-dim' },
  };
  const c = cfg[status] || cfg.UNKNOWN;
  return (
    <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-semibold ${c.light} ${c.dark}`}>
      <span className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${c.dot} ${status === 'UP' ? '[animation:glow-pulse_2s_ease-in-out_infinite]' : ''}`} />
      {status || 'UNKNOWN'}
    </span>
  );
}
